//! agent-scaffold: scaffold the agent workflow into a project.
//!
//! Two-tier ownership from the spec:
//!
//! - Reference assets (tool-owned, under `.agents/`) are always refreshed.
//! - Working files (the root `AGENTS.md` and the plan template) are
//!   create-if-absent unless `--force`.
//!
//! `AGENTS.md` is generated by rendering the selected principles into the
//! pack's guidance template; the other assets are dropped verbatim.

mod manifest;
mod pack;
mod tui;

use {
	clap::Parser,
	manifest::{
		Asset,
		Ownership,
	},
	pack::Detail,
	std::{
		collections::HashMap,
		fs,
		io::{
			self,
			IsTerminal,
			Write,
		},
		path::{
			Path,
			PathBuf,
		},
	},
};

/// What happened to a single asset on a scaffold run.
#[derive(Debug, PartialEq, Eq)]
enum Outcome {
	Created,
	Refreshed,
	SkippedExisting,
	Overwritten,
}

impl Outcome {
	/// Present-tense label for the plan preview: what the action would do.
	fn plan_label(&self) -> &'static str {
		match self {
			Outcome::Created => "create",
			Outcome::Refreshed => "refresh",
			Outcome::SkippedExisting => "skip (exists)",
			Outcome::Overwritten => "overwrite",
		}
	}
}

/// Decide, without touching the filesystem, what would happen to `asset` under
/// `root`. This drives the dry-run preview, so it must not write.
fn outcome_of(
	root: &Path,
	asset: &Asset,
	force: bool,
) -> Outcome {
	let exists = root.join(&asset.dest).exists();
	match asset.ownership {
		Ownership::Reference =>
			if exists {
				Outcome::Refreshed
			} else {
				Outcome::Created
			},
		Ownership::Working =>
			if exists {
				if force { Outcome::Overwritten } else { Outcome::SkippedExisting }
			} else {
				Outcome::Created
			},
	}
}

/// Write `asset` under `root`, unless the planned outcome is to skip it.
fn apply_asset(
	root: &Path,
	asset: &Asset,
	outcome: &Outcome,
) -> io::Result<()> {
	if matches!(outcome, Outcome::SkippedExisting) {
		return Ok(());
	}
	let dest = root.join(&asset.dest);
	if let Some(parent) = dest.parent() {
		fs::create_dir_all(parent)?;
	}
	fs::write(&dest, &asset.contents)
}

/// The active pack's principle set: parse its `principles.toml`, or an empty set
/// when the pack ships none. A malformed `principles.toml` is a parse error. For
/// the built-in pack this reads the same embedded file the drop uses, so the
/// selection and the dropped `principles.toml` stay consistent.
fn pack_principles(source: &manifest::PackSource) -> Result<Vec<pack::Principle>, toml::de::Error> {
	match source.read("principles.toml") {
		Ok(toml) => pack::parse_principles(&toml),
		// A pack that ships no principles.toml simply has no principles to select.
		Err(_) => Ok(Vec::new()),
	}
}

/// Build the asset set to drop from the active pack: `{{principles}}` is
/// rendered from the current selection and `overrides` supplies the `--var`
/// values for any variables the pack declares. Building does not write.
fn build_assets(
	source: &manifest::PackSource,
	selected: &[&pack::Principle],
	detail: Detail,
	overrides: &HashMap<String, String>,
) -> Result<Vec<Asset>, manifest::LoadError> {
	let mut builtin: HashMap<String, String> = HashMap::new();
	builtin.insert("principles".to_string(), pack::render_principles(selected, detail));
	manifest::load(source, &builtin, overrides)
}

/// Ask on the terminal whether to apply the previewed changes. The default is
/// No, so an empty line (or anything but yes) declines.
fn confirm_write() -> io::Result<bool> {
	print!("Apply these changes? [y/N]: ");
	io::stdout().flush()?;
	let mut answer = String::new();
	io::stdin().read_line(&mut answer)?;
	Ok(matches!(answer.trim(), "y" | "Y" | "yes" | "Yes" | "YES"))
}

/// Build and write the asset set, returning each asset's path and outcome. A
/// convenience for tests; `main` drives build, plan, and apply separately so it
/// can preview and confirm before writing.
#[cfg(test)]
fn scaffold(
	source: &manifest::PackSource,
	root: &Path,
	selected: &[&pack::Principle],
	detail: Detail,
	overrides: &HashMap<String, String>,
	force: bool,
) -> Result<Vec<(String, Outcome)>, manifest::LoadError> {
	build_assets(source, selected, detail, overrides)?
		.into_iter()
		.map(|asset| {
			let outcome = outcome_of(root, &asset, force);
			apply_asset(root, &asset, &outcome).map(|()| (asset.dest, outcome))
		})
		.collect::<io::Result<Vec<_>>>()
		.map_err(manifest::LoadError::from)
}

/// Scaffold the agent workflow into a project.
#[derive(Parser)]
#[command(name = "agent-scaffold", about, version)]
struct Cli {
	/// Directory to scaffold into (defaults to the current directory).
	#[arg(long, default_value = ".")]
	output_dir: PathBuf,
	/// Overwrite existing user working files instead of leaving them untouched.
	#[arg(long)]
	force: bool,
	/// Write the changes. Without it a run previews the plan and, on a terminal, asks to confirm.
	#[arg(long)]
	write: bool,
	/// Which principles to include: default, all, none, or a comma-separated list of ids.
	#[arg(long, default_value = "default")]
	principles: String,
	/// How much of each principle to render into the output.
	#[arg(long, value_enum, default_value_t = Detail::Summary)]
	principle_detail: Detail,
	/// Print the default-selected principles (numbered) and exit, without scaffolding.
	#[arg(long)]
	list_principles: bool,
	/// Choose principles interactively in a two-pane selector, seeded from `--principles`.
	#[arg(long, short)]
	interactive: bool,
	/// Scaffold from a user-supplied pack directory instead of the built-in one.
	#[arg(long)]
	template: Option<PathBuf>,
	/// Set a pack-declared variable, as `--var key=value` (repeatable).
	#[arg(long = "var", value_name = "KEY=VALUE")]
	var: Vec<String>,
}

fn main() -> io::Result<()> {
	let cli = Cli::parse();

	// The active pack: the built-in one, or an external directory via --template.
	let source = match &cli.template {
		Some(path) => manifest::PackSource::Directory(path.clone()),
		None => manifest::builtin(),
	};

	// Parse --var key=value overrides. Validation against the pack's declared
	// variables happens in the loader; here we only reject malformed entries.
	let mut overrides: HashMap<String, String> = HashMap::new();
	for entry in &cli.var {
		match entry.split_once('=') {
			Some((key, value)) => {
				overrides.insert(key.to_string(), value.to_string());
			}
			None => {
				eprintln!("error: --var expects key=value, got `{entry}`");
				std::process::exit(2);
			}
		}
	}

	// Principles are a property of the active pack: the built-in set, or the
	// external pack's own principles.toml under --template.
	let principles = match pack_principles(&source) {
		Ok(principles) => principles,
		Err(error) => {
			eprintln!("error: could not parse the pack's principles.toml: {error}");
			std::process::exit(2);
		}
	};
	let selected = match pack::resolve_selection(&principles, &cli.principles) {
		Ok(selected) => selected,
		Err(error) => {
			eprintln!("error: {error}");
			std::process::exit(2);
		}
	};

	if cli.list_principles {
		println!("{}", pack::render_principles(&selected, cli.principle_detail));
		return Ok(());
	}

	// Interactive selection overrides the resolved set, seeded from it. On
	// confirm it prints a `--principles` line so the exact selection and order
	// can be replayed non-interactively; on abort nothing is written.
	let selected = if cli.interactive {
		let initial: Vec<usize> = selected
			.iter()
			.map(|p| {
				principles
					.iter()
					.position(|q| q.id == p.id)
					.expect("selected principle is from the pack")
			})
			.collect();
		let save_summary = vec![
			format!("Scaffold into: {}", cli.output_dir.display()),
			"Creates AGENTS.md and docs/plans/TEMPLATE.md if absent;".to_string(),
			"always refreshes the .agents/ reference assets.".to_string(),
			if cli.force {
				"Existing working files WILL be overwritten (--force).".to_string()
			} else {
				"Existing working files are left untouched.".to_string()
			},
		];
		match tui::run_selection(&principles, &initial, save_summary)? {
			Some(order) => {
				let chosen: Vec<&pack::Principle> = order.iter().map(|&i| &principles[i]).collect();
				let ids: Vec<&str> = chosen.iter().map(|p| p.id.as_str()).collect();
				println!("selection: --principles {}", ids.join(","));
				chosen
			}
			None => {
				eprintln!("aborted; nothing written");
				return Ok(());
			}
		}
	} else {
		selected
	};

	let assets = match build_assets(&source, &selected, cli.principle_detail, &overrides) {
		Ok(assets) => assets,
		Err(error) => {
			eprintln!("error: {error}");
			std::process::exit(2);
		}
	};
	let outcomes: Vec<Outcome> =
		assets.iter().map(|asset| outcome_of(&cli.output_dir, asset, cli.force)).collect();

	// Preview the plan, then decide whether to write. Writes are off by default:
	// interactive Save (the modal) and --write both mean "write"; otherwise, on a
	// terminal, ask for y/N (default No); with no terminal (a pipe or CI), stay a
	// dry run and write nothing.
	for (asset, outcome) in assets.iter().zip(&outcomes) {
		println!("{:>16}  {}", outcome.plan_label(), asset.dest);
	}

	let write = cli.interactive || cli.write || (io::stdin().is_terminal() && confirm_write()?);
	if write {
		for (asset, outcome) in assets.iter().zip(&outcomes) {
			apply_asset(&cli.output_dir, asset, outcome)?;
		}
		let changed = outcomes.iter().filter(|o| !matches!(o, Outcome::SkippedExisting)).count();
		let untouched = outcomes.len() - changed;
		println!(
			"Wrote to {} ({changed} changed, {untouched} left untouched).",
			cli.output_dir.display()
		);
	} else if io::stdin().is_terminal() {
		println!("Aborted; nothing written.");
	} else {
		println!("Dry run; nothing written. Pass --write to apply.");
	}
	Ok(())
}

#[cfg(test)]
mod tests {
	use super::*;

	/// A unique scratch directory under the system temp dir for one test.
	fn scratch(name: &str) -> PathBuf {
		let dir = std::env::temp_dir().join(format!(
			"agent-scaffold-poc-{}-{}",
			std::process::id(),
			name
		));
		let _ = fs::remove_dir_all(&dir);
		dir
	}

	#[test]
	fn planning_does_not_write() {
		// The dry-run preview computes outcomes without touching the filesystem.
		let root = scratch("plan-only");
		let principles = pack::default_principles();
		let selected = pack::resolve_selection(&principles, "default").unwrap();
		let assets =
			build_assets(&manifest::builtin(), &selected, Detail::Summary, &HashMap::new())
				.unwrap();
		let outcomes: Vec<Outcome> =
			assets.iter().map(|asset| outcome_of(&root, asset, false)).collect();

		assert!(!outcomes.is_empty());
		assert!(outcomes.iter().all(|o| *o == Outcome::Created), "a fresh dir plans all-Created");
		assert!(!root.exists(), "planning must not create the output directory");
	}

	#[test]
	fn builtin_principles_come_from_the_embedded_pack() {
		// The built-in path reads through the same source the scaffold uses and
		// matches the convenience helper the other tests rely on.
		let via_source = pack_principles(&manifest::builtin()).unwrap();
		assert!(!via_source.is_empty());
		assert_eq!(via_source.len(), pack::default_principles().len());
	}

	#[test]
	fn template_principles_come_from_the_pack_not_the_builtin() {
		let root = scratch("tpl-principles");
		fs::create_dir_all(&root).unwrap();
		fs::write(
			root.join("principles.toml"),
			"[[principle]]\nid = \"custom-one\"\nname = \"Custom One\"\nsummary = \"s\"\n\
			 rationale = \"r\"\ntags = [\"x\"]\ndefault_selected = true\ndefault_order = 1\n",
		)
		.unwrap();
		let principles = pack_principles(&manifest::PackSource::Directory(root.clone())).unwrap();
		assert_eq!(principles.len(), 1);
		assert_eq!(principles[0].id, "custom-one");
		fs::remove_dir_all(&root).unwrap();
	}

	#[test]
	fn a_pack_without_principles_has_an_empty_set() {
		let root = scratch("tpl-no-principles");
		fs::create_dir_all(&root).unwrap();
		let principles = pack_principles(&manifest::PackSource::Directory(root.clone())).unwrap();
		assert!(principles.is_empty());
		fs::remove_dir_all(&root).unwrap();
	}

	#[test]
	fn first_run_creates_everything() {
		let root = scratch("first-run");
		let principles = pack::default_principles();
		let selected = pack::resolve_selection(&principles, "default").unwrap();
		let results = scaffold(
			&manifest::builtin(),
			&root,
			&selected,
			Detail::Summary,
			&HashMap::new(),
			false,
		)
		.unwrap();
		assert!(results.iter().all(|(_, o)| *o == Outcome::Created));
		assert!(root.join("AGENTS.md").exists());
		assert!(root.join(".agents/principles.toml").exists());
		fs::remove_dir_all(&root).unwrap();
	}

	#[test]
	fn generated_agents_has_principles_and_no_placeholder() {
		let root = scratch("generated");
		let principles = pack::default_principles();
		let selected = pack::resolve_selection(&principles, "default").unwrap();
		scaffold(&manifest::builtin(), &root, &selected, Detail::Summary, &HashMap::new(), false)
			.unwrap();
		let agents = fs::read_to_string(root.join("AGENTS.md")).unwrap();
		assert!(!agents.contains("{{principles}}"));
		assert!(agents.contains("1. "));
		fs::remove_dir_all(&root).unwrap();
	}

	#[test]
	fn rerun_refreshes_reference_but_skips_working() {
		let root = scratch("rerun");
		let principles = pack::default_principles();
		let selected = pack::resolve_selection(&principles, "default").unwrap();
		scaffold(&manifest::builtin(), &root, &selected, Detail::Summary, &HashMap::new(), false)
			.unwrap();

		// A user edits a working file after the first run.
		fs::write(root.join("AGENTS.md"), "user edits\n").unwrap();

		let results = scaffold(
			&manifest::builtin(),
			&root,
			&selected,
			Detail::Summary,
			&HashMap::new(),
			false,
		)
		.unwrap();
		let outcome_of =
			|p: &str| results.iter().find(|(path, _)| *path == p).map(|(_, o)| o).unwrap();

		// Reference assets are refreshed; the edited working file is left alone.
		assert_eq!(*outcome_of(".agents/principles.toml"), Outcome::Refreshed);
		assert_eq!(*outcome_of("AGENTS.md"), Outcome::SkippedExisting);
		assert_eq!(fs::read_to_string(root.join("AGENTS.md")).unwrap(), "user edits\n");
		fs::remove_dir_all(&root).unwrap();
	}

	#[test]
	fn force_overwrites_working_files() {
		let root = scratch("force");
		let principles = pack::default_principles();
		let selected = pack::resolve_selection(&principles, "default").unwrap();
		scaffold(&manifest::builtin(), &root, &selected, Detail::Summary, &HashMap::new(), false)
			.unwrap();
		fs::write(root.join("AGENTS.md"), "user edits\n").unwrap();

		let results = scaffold(
			&manifest::builtin(),
			&root,
			&selected,
			Detail::Summary,
			&HashMap::new(),
			true,
		)
		.unwrap();
		let agents = results.iter().find(|(path, _)| *path == "AGENTS.md").map(|(_, o)| o).unwrap();
		assert_eq!(*agents, Outcome::Overwritten);
		let contents = fs::read_to_string(root.join("AGENTS.md")).unwrap();
		assert_ne!(contents, "user edits\n");
		assert!(contents.starts_with("# Agent guidance"));
		fs::remove_dir_all(&root).unwrap();
	}
}
